const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const call_id = body.call_id || null;
if (!call_id) return { json: { _error: true, error: 'call_id required', ok: false } };
return { json: { call_id, agent_id: body.agent_id || null, lead_id: body.lead_id || null } };

const chunks = Array.isArray($input.item.json) ? $input.item.json : [];
const parsed = $('Parse Input').first().json;
if (chunks.length === 0) return { json: { _skip: true, reason: 'no chunks', call_id: parsed.call_id } };

const transcript = chunks.map(function(c) { return '[' + (c.speaker || '?') + '] ' + (c.transcript_text || ''); }).join('\n');
const intents = chunks.map(function(c) { return c.detected_intent || 'unknown'; });
const closing_count = intents.filter(function(i) { return i === 'closing_signal'; }).length;
const buy_count     = intents.filter(function(i) { return i === 'buy_signal'; }).length;

const system_prompt = [
  'You are a senior sales-call analyst for Crystallux.',
  'Review the call transcript + chunk-level intents and produce structured coaching notes.',
  'Output STRICT JSON only with these keys:',
  '{',
  '  "overall_sentiment": "positive|neutral|negative|mixed",',
  '  "sentiment_trajectory": [{"chunk_range": "1-10", "sentiment": "neutral"}, ...],',
  '  "key_objections": ["..."],',
  '  "closing_signals_detected": number,',
  '  "buy_signals_detected": number,',
  '  "opportunities_missed": ["short factual note..."],',
  '  "coaching_recommendations": ["practice ..."],',
  '  "call_outcome_prediction": "likely_closed|warm|cold|follow_up_needed",',
  '  "transcript_quality": "excellent|good|fair|poor|failed"',
  '}'
].join('\n');

const user_prompt = 'CHUNK INTENTS: ' + intents.join(',') + '\n\nTRANSCRIPT:\n' + transcript.slice(0, 12000);

return { json: Object.assign({}, parsed, { system_prompt, user_prompt, _closing_count: closing_count, _buy_count: buy_count }) };

const resp = $input.item.json || {};
const prep = $('Prep Prompt').first().json;
let parsed = null;
try {
  const text = (resp.content && resp.content[0] && resp.content[0].text) || '';
  if (text.trim().length > 0) parsed = JSON.parse(text.trim());
} catch (e) { parsed = null; }

if (!parsed) {
  parsed = {
    overall_sentiment: 'unknown',
    sentiment_trajectory: [],
    key_objections: [],
    closing_signals_detected: prep._closing_count || 0,
    buy_signals_detected: prep._buy_count || 0,
    opportunities_missed: ['Claude unavailable — heuristic fallback only'],
    coaching_recommendations: [],
    call_outcome_prediction: 'follow_up_needed',
    transcript_quality: 'fair'
  };
}

return { json: Object.assign({}, prep, { analysis: parsed }) };

const upsert = $input.item.json;
const prep = $('Parse Analysis').first().json;
let event_id = null;
if (typeof upsert === 'string') event_id = upsert;
else if (upsert && upsert.id) event_id = upsert.id;
else if (Array.isArray(upsert) && upsert.length > 0 && upsert[0].finalize_call_analysis) event_id = upsert[0].finalize_call_analysis;
return { json: { ok: event_id != null, call_id: prep.call_id, event_id, analysis: prep.analysis } };
